import { useState, useEffect } from "react";
import NavbarGestionSalas from "../components/NavbarGestionSalas";
import "../styles/EditarSala.css";

function EditarSala() {
  const [salas, setSalas] = useState([]);
  const [salaSeleccionada, setSalaSeleccionada] = useState(null);
  const [form, setForm] = useState({
    nombre: "",
    ubicacion: "",
    capacidad: ""
  });
  const [mensaje, setMensaje] = useState("");

  // Cargar salas al iniciar
  useEffect(() => {
    fetch("http://localhost:3001/api/salas")
      .then(res => res.json())
      .then(data => setSalas(data))
      .catch(err => console.error(err));
  }, []);

  // Seleccionar sala para editar
  const seleccionarSala = (sala) => {
    setSalaSeleccionada(sala);
    setForm({
      nombre: sala.nombre,
      ubicacion: sala.ubicacion,
      capacidad: sala.capacidad
    });
  };

  // Manejar cambios en el formulario
  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // Enviar edición al backend
  const handleEditar = async () => {
    if (!salaSeleccionada) {
      setMensaje("Selecciona una sala primero");
      return;
    }

    try {
      const res = await fetch(`http://localhost:3001/api/salas/${salaSeleccionada.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form)
      });

      const data = await res.json();

      if (res.ok) {
        setMensaje("Sala editada exitosamente");
        setSalas(salas.map(s => s.id === salaSeleccionada.id ? data : s));
      } else {
        setMensaje(data.error || "Error al editar");
      }
    } catch (err) {
      setMensaje("Error de conexión");
    }
  };

  return (
    <div className="container">
      <NavbarGestionSalas />

      <div className="content">

        {/* IZQUIERDA - FORMULARIO */}
        <div className="formSection">
          <h3>Sala No° {salaSeleccionada ? salaSeleccionada.id : ""}</h3>

          {mensaje && <p style={{ color: "green" }}>{mensaje}</p>}

          <div className="formGroup">
            <label>Nombre:</label>
            <input
              type="text"
              name="nombre"
              value={form.nombre}
              onChange={handleChange}
            />
          </div>

          <div className="formGroup">
            <label>Ubicación:</label>
            <input
              type="text"
              name="ubicacion"
              value={form.ubicacion}
              onChange={handleChange}
            />
          </div>

          <div className="formGroup">
            <label>Capacidad:</label>
            <input
              type="number"
              name="capacidad"
              value={form.capacidad}
              onChange={handleChange}
            />
          </div>

          <button className="editarBtn" onClick={handleEditar}>Editar</button>
        </div>

        {/* DERECHA - LISTA DE SALAS */}
        <div className="listSection">
          {salas.length === 0 ? (
            <div className="emptyState">
              <p>No hay salas creadas</p>
            </div>
          ) : (
            salas.map(sala => (
              <div
                key={sala.id}
                className="salaItem"
                onClick={() => seleccionarSala(sala)}
                style={{
                  cursor: "pointer",
                  background: salaSeleccionada?.id === sala.id ? "#f0f0f0" : "white",
                  padding: "10px",
                  marginBottom: "8px",
                  border: "1px solid #ccc",
                  borderRadius: "6px"
                }}
              >
                <p><strong>{sala.nombre}</strong></p>
                <p>{sala.ubicacion} — {sala.capacidad} personas</p>
                <p>Estado: {sala.estado}</p>
              </div>
            ))
          )}
        </div>

      </div>

      <div className="footer">
        <button className="nextBtn">→</button>
      </div>
    </div>
  );
}

export default EditarSala
